     1→/**
     2→ * Diagram Editor Store
     3→ * Manages editor state (tool, selection, clipboard, undo/redo)
     4→ */
     5→
     6→import { create } from 'zustand';
     7→import { persist } from 'zustand/middleware';
     8→import type { DiagramElement, ToolType, HistoryEntry, CanvasState, AlignmentType, DrawingStyle } from '../types/diagrams';
     9→
    10→interface DiagramEditorState {
    11→  // Current tool
    12→  currentTool: ToolType;
    13→  setCurrentTool: (tool: ToolType) => void;
    14→
    15→  // P0: Shape palette state
    16→  shapePaletteOpen: boolean;
    17→  toggleShapePalette: () => void;
    18→
    19→  // P1: Layer panel state
    20→  layerPanelOpen: boolean;
    21→  toggleLayerPanel: () => void;
    22→
    23→  // P2: Hand-drawn style settings
    24→  globalDrawingStyle: DrawingStyle;
    25→  globalRoughness: number;
    26→  globalBowing: number;
    27→  setGlobalDrawingStyle: (style: DrawingStyle) => void;
    28→  setGlobalRoughness: (roughness: number) => void;
    29→  setGlobalBowing: (bowing: number) => void;
    30→
    31→  // Selection
    32→  selectedElementIds: string[];
    33→  selectElement: (id: string, addToSelection?: boolean) => void;
    34→  selectMultiple: (ids: string[]) => void;
    35→  clearSelection: () => void;
    36→  isSelected: (id: string) => boolean;
    37→
    38→  // Clipboard
    39→  clipboard: DiagramElement[];
    40→  copy: (elements: DiagramElement[]) => void;
    41→  paste: () => DiagramElement[];
    42→
    43→  // Drawing state
    44→  isDragging: boolean;
    45→  isDrawing: boolean;
    46→  setIsDragging: (dragging: boolean) => void;
    47→  setIsDrawing: (drawing: boolean) => void;
    48→
    49→  // P0: Grouping (receives elements + callback to update diagram)
    50→  groupElements: (elements: DiagramElement[], onUpdate: (updates: DiagramElement[]) => void) => string;
    51→  ungroupElements: (elements: DiagramElement[], groupId: string, onUpdate: (updates: DiagramElement[]) => void) => void;
    52→  getGroupId: (elementId: string, elements: DiagramElement[]) => string | undefined;
    53→
    54→  // P0: Alignment (receives elements + callback to update diagram)
    55→  alignElements: (
    56→    elementIds: string[],
    57→    elements: DiagramElement[],
    58→    type: AlignmentType,
    59→    onUpdate: (updates: DiagramElement[]) => void
    60→  ) => void;
    61→
    62→  // Undo/Redo
    63→  history: HistoryEntry[];
    64→  currentHistoryIndex: number;
    65→  maxHistorySize: number;
    66→  pushHistory: (elements: DiagramElement[], canvasState: CanvasState) => void;
    67→  undo: () => HistoryEntry | undefined;
    68→  redo: () => HistoryEntry | undefined;
    69→  canUndo: () => boolean;
    70→  canRedo: () => boolean;
    71→}
    72→
    73→export const useDiagramEditorStore = create<DiagramEditorState>()(
    74→  persist(
    75→    (set, get) => ({
    76→  // Tool
    77→  currentTool: 'select',
    78→  setCurrentTool: (tool) => set({ currentTool: tool }),
    79→
    80→  // P0: Shape palette
    81→  shapePaletteOpen: true,
    82→  toggleShapePalette: () => set((state) => ({ shapePaletteOpen: !state.shapePaletteOpen })),
    83→
    84→  // P1: Layer panel
    85→  layerPanelOpen: true,
    86→  toggleLayerPanel: () => set((state) => ({ layerPanelOpen: !state.layerPanelOpen })),
    87→
    88→  // P2: Hand-drawn style settings
    89→  globalDrawingStyle: 'normal',
    90→  globalRoughness: 1.5,
    91→  globalBowing: 1,
    92→  setGlobalDrawingStyle: (style) => set({ globalDrawingStyle: style }),
    93→  setGlobalRoughness: (roughness) => set({ globalRoughness: roughness }),
    94→  setGlobalBowing: (bowing) => set({ globalBowing: bowing }),
    95→
    96→  // Selection
    97→  selectedElementIds: [],
    98→
    99→  selectElement: (id, addToSelection = false) => {
   100→    set((state) => {
   101→      if (addToSelection) {
   102→        // Toggle selection
   103→        const isCurrentlySelected = state.selectedElementIds.includes(id);
   104→        return {
   105→          selectedElementIds: isCurrentlySelected
   106→            ? state.selectedElementIds.filter((sid) => sid !== id)
   107→            : [...state.selectedElementIds, id],
   108→        };
   109→      } else {
   110→        return { selectedElementIds: [id] };
   111→      }
   112→    });
   113→  },
   114→
   115→  selectMultiple: (ids) => set({ selectedElementIds: ids }),
   116→
   117→  clearSelection: () => set({ selectedElementIds: [] }),
   118→
   119→  isSelected: (id) => get().selectedElementIds.includes(id),
   120→
   121→  // Clipboard
   122→  clipboard: [],
   123→
   124→  copy: (elements) => {
   125→    set({ clipboard: elements.map((el) => ({ ...el })) });
   126→  },
   127→
   128→  paste: () => {
   129→    const { clipboard } = get();
   130→    if (clipboard.length === 0) return [];
   131→
   132→    // Create new elements with new IDs and offset position
   133→    const pastedElements = clipboard.map((el) => ({
   134→      ...el,
   135→      id: crypto.randomUUID(),
   136→      x: el.x + 20, // Offset by 20px
   137→      y: el.y + 20,
   138→    }));
   139→
   140→    return pastedElements;
   141→  },
   142→
   143→  // Drawing state
   144→  isDragging: false,
   145→  isDrawing: false,
   146→  setIsDragging: (dragging) => set({ isDragging: dragging }),
   147→  setIsDrawing: (drawing) => set({ isDrawing: drawing }),
   148→
   149→  // P0: Grouping
   150→  groupElements: (elements, onUpdate) => {
   151→    const { selectedElementIds } = get();
   152→    const groupId = crypto.randomUUID();
   153→
   154→    // Assign groupId to selected elements
   155→    const updatedElements = elements.map((el) =>
   156→      selectedElementIds.includes(el.id) ? { ...el, groupId } : el
   157→    );
   158→
   159→    onUpdate(updatedElements);
   160→    return groupId;
   161→  },
   162→
   163→  ungroupElements: (elements, groupId, onUpdate) => {
   164→    // Remove groupId from elements in the group
   165→    const updatedElements = elements.map((el) =>
   166→      el.groupId === groupId ? { ...el, groupId: undefined } : el
   167→    );
   168→
   169→    onUpdate(updatedElements);
   170→  },
   171→
   172→  getGroupId: (elementId, elements) => {
   173→    const element = elements.find((el) => el.id === elementId);
   174→    return element?.groupId;
   175→  },
   176→
   177→  // P0: Alignment
   178→  alignElements: (elementIds, elements, type, onUpdate) => {
   179→    const selectedElements = elements.filter((el) => elementIds.includes(el.id));
   180→    if (selectedElements.length < 2) return;
   181→
   182→    // Calculate bounding box for alignment reference
   183→    const getBounds = (el: DiagramElement) => {
   184→      const rotation = el.rotation || 0;
   185→      if (rotation === 0) {
   186→        return {
   187→          left: el.x,
   188→          right: el.x + el.width,
   189→          top: el.y,
   190→          bottom: el.y + el.height,
   191→          centerX: el.x + el.width / 2,
   192→          centerY: el.y + el.height / 2,
   193→        };
   194→      }
   195→
   196→      // For rotated shapes, use the center point
   197→      return {
   198→        left: el.x,
   199→        right: el.x + el.width,
   200→        top: el.y,
   201→        bottom: el.y + el.height,
   202→        centerX: el.x + el.width / 2,
   203→        centerY: el.y + el.height / 2,
   204→      };
   205→    };
   206→
   207→    const bounds = selectedElements.map((el) => ({
   208→      element: el,
   209→      bounds: getBounds(el),
   210→    }));
   211→
   212→    let updatedElements = [...elements];
   213→
   214→    switch (type) {
   215→      case 'left': {
   216→        const leftmost = Math.min(...bounds.map((b) => b.bounds.left));
   217→        updatedElements = elements.map((el) => {
   218→          const bound = bounds.find((b) => b.element.id === el.id);
   219→          return bound ? { ...el, x: leftmost } : el;
   220→        });
   221→        break;
   222→      }
   223→
   224→      case 'center': {
   225→        const centerX =
   226→          bounds.reduce((sum, b) => sum + b.bounds.centerX, 0) / bounds.length;
   227→        updatedElements = elements.map((el) => {
   228→          const bound = bounds.find((b) => b.element.id === el.id);
   229→          return bound ? { ...el, x: centerX - el.width / 2 } : el;
   230→        });
   231→        break;
   232→      }
   233→
   234→      case 'right': {
   235→        const rightmost = Math.max(...bounds.map((b) => b.bounds.right));
   236→        updatedElements = elements.map((el) => {
   237→          const bound = bounds.find((b) => b.element.id === el.id);
   238→          return bound ? { ...el, x: rightmost - el.width } : el;
   239→        });
   240→        break;
   241→      }
   242→
   243→      case 'top': {
   244→        const topmost = Math.min(...bounds.map((b) => b.bounds.top));
   245→        updatedElements = elements.map((el) => {
   246→          const bound = bounds.find((b) => b.element.id === el.id);
   247→          return bound ? { ...el, y: topmost } : el;
   248→        });
   249→        break;
   250→      }
   251→
   252→      case 'middle': {
   253→        const centerY =
   254→          bounds.reduce((sum, b) => sum + b.bounds.centerY, 0) / bounds.length;
   255→        updatedElements = elements.map((el) => {
   256→          const bound = bounds.find((b) => b.element.id === el.id);
   257→          return bound ? { ...el, y: centerY - el.height / 2 } : el;
   258→        });
   259→        break;
   260→      }
   261→
   262→      case 'bottom': {
   263→        const bottommost = Math.max(...bounds.map((b) => b.bounds.bottom));
   264→        updatedElements = elements.map((el) => {
   265→          const bound = bounds.find((b) => b.element.id === el.id);
   266→          return bound ? { ...el, y: bottommost - el.height } : el;
   267→        });
   268→        break;
   269→      }
   270→
   271→      case 'distribute': {
   272→        // Determine orientation based on variance
   273→        const xVariance = Math.max(...bounds.map((b) => b.bounds.centerX)) - Math.min(...bounds.map((b) => b.bounds.centerX));
   274→        const yVariance = Math.max(...bounds.map((b) => b.bounds.centerY)) - Math.min(...bounds.map((b) => b.bounds.centerY));
   275→
   276→        if (xVariance > yVariance) {
   277→          // Distribute horizontally
   278→          const sorted = [...bounds].sort((a, b) => a.bounds.centerX - b.bounds.centerX);
   279→          const first = sorted[0].bounds.centerX;
   280→          const last = sorted[sorted.length - 1].bounds.centerX;
   281→          const spacing = (last - first) / (sorted.length - 1);
   282→
   283→          updatedElements = elements.map((el) => {
   284→            const index = sorted.findIndex((s) => s.element.id === el.id);
   285→            if (index === -1) return el;
   286→            const newCenterX = first + spacing * index;
   287→            return { ...el, x: newCenterX - el.width / 2 };
   288→          });
   289→        } else {
   290→          // Distribute vertically
   291→          const sorted = [...bounds].sort((a, b) => a.bounds.centerY - b.bounds.centerY);
   292→          const first = sorted[0].bounds.centerY;
   293→          const last = sorted[sorted.length - 1].bounds.centerY;
