   104→  const handleTransformEnd = (id: string, e: Konva.KonvaEventObject<Event>) => {
   105→    const node = e.target;
   106→    const scaleX = node.scaleX();
   107→    const scaleY = node.scaleY();
   108→
   109→    // Reset scale and update width/height
   110→    node.scaleX(1);
   111→    node.scaleY(1);
   112→
   113→    const updatedElements = elements.map((el) =>
   114→      el.id === id
   115→        ? {
   116→            ...el,
   117→            x: node.x(),
   118→            y: node.y(),
   119→            width: Math.max(5, node.width() * scaleX),
   120→            height: Math.max(5, node.height() * scaleY),
   121→            rotation: node.rotation(),
   122→          }
   123→        : el
   124→    );
   125→
   126→    setElements(updatedElements);
   127→    updateDiagram(diagramId, { elements: updatedElements });
   128→  };
